module.render:
const bg = args.bg || 'transparent';
const border = args.border || '0';
// halign = horizontal (left/center/right), valign = vertical (top/middle/bottom).
const h = (args.halign || 'center').toLowerCase();
const v = (args.valign || 'middle').toLowerCase();
// valign positions the whole content block on the column's main axis.
const justify = v === 'top' ? 'flex-start' : v === 'bottom' ? 'flex-end' : 'center';
// halign is handled via text-align; content stretches to the full box width
// (align-items: stretch) so paragraphs/tables/images use the available width.
const textAlign = h === 'left' ? 'left' : h === 'right' ? 'right' : 'center';
const radius = Math.max(0, Math.min(200, Number.isFinite(parseFloat(args.radius)) ? parseFloat(args.radius) : 6));
const pad = Math.max(0, Math.min(400, Number.isFinite(parseFloat(args.padding)) ? parseFloat(args.padding) : 0));
const shadowCss = String(args.shadow) === 'true' ? '0 2px 12px rgba(0,0,0,0.18)' : 'none';
const textcolor = (args.textcolor && String(args.textcolor).trim()) ? args.textcolor : '';
const colorCss = textcolor ? ` color:${textcolor};` : '';
const body = (sections[0] || '').trim();
return `\n\n<div class="mdp-mod-freebox" style="background:${bg}; border:${border}; border-radius:${radius}px; padding:${pad}px; box-shadow:${shadowCss};${colorCss} align-items: stretch; justify-content:${justify}; text-align:${textAlign};">\n\n${body}\n\n</div>\n\n`;
